Script:
```
#!/usr/bin/env python3
# extract_codes.py
# Usage: edit the IMAP/credentials section below, then run locally.

import imaplib
import email
import re
from datetime import datetime, timedelta
import requests
from email.header import decode_header
from email.utils import parsedate_to_datetime
import json
import ssl

# ---------- Configuration ----------
IMAP_HOST = "imap.gmail.com"       # change if needed
EMAIL_ACCOUNT = "your_email@example.com"
EMAIL_PASSWORD = "your_imap_or_app_password"
MAILBOX = "INBOX"
# ---------- End configuration ----------

def decode_mime_words(s):
    parts = decode_header(s)
    out = ""
    for text, enc in parts:
        if isinstance(text, bytes):
            out += text.decode(enc or "utf-8", errors="replace")
        else:
            out += text
    return out

def search_recent_uids(imap, since_days=7):
    since_date = (datetime.utcnow() - timedelta(days=since_days)).strftime("%d-%b-%Y")
    # Search all messages since since_date
    typ, data = imap.search(None, '(SINCE "{}")'.format(since_date))
    if typ != "OK":
        return []
    uids = data[0].split()
    return uids[::-1]  # newest first

def fetch_message(imap, uid):
    typ, data = imap.fetch(uid, "(RFC822)")
    if typ != "OK" or not data or not data[0]:
        return None
    msg = email.message_from_bytes(data[0][1])
    return msg

def get_header(msg, name):
    val = msg.get(name, "")
    return decode_mime_words(val)

def get_text_from_msg(msg):
    if msg.is_multipart():
        for part in msg.walk():
            ctype = part.get_content_type()
            if ctype == "text/plain":
                try:
                    return part.get_payload(decode=True).decode(part.get_content_charset() or "utf-8", errors="replace")
                except:
                    continue
        # fallback to first text/html
        for part in msg.walk():
            ctype = part.get_content_type()
            if ctype == "text/html":
                try:
                    return part.get_payload(decode=True).decode(part.get_content_charset() or "utf-8", errors="replace")
                except:
                    continue
        return ""
    else:
        try:
            return msg.get_payload(decode=True).decode(msg.get_content_charset() or "utf-8", errors="replace")
        except:
            return ""

def find_facebook_code(text):
    # look for lines that mention Facebook and a 5-8 digit code nearby
    # common phrases: "security code", "Facebook code"
    # search contexts
    candidates = re.findall(r'(?:Facebook|security code|code)\D{0,30}(\d{5,8})', text, flags=re.IGNORECASE)
    if candidates:
        return candidates[0]
    # fallback: any 5-8 digit number
    m = re.search(r'\b(\d{5,8})\b', text)
    return m.group(1) if m else None

def find_first_url(text):
    m = re.search(r'https?://[^\s\)\]\>\"]+', text)
    return m.group(0) if m else None

def iso_date_from_header(msg):
    date_hdr = msg.get("Date")
    try:
        dt = parsedate_to_datetime(date_hdr)
        return dt.astimezone().isoformat()
    except Exception:
        return None

def validate_url_head(url, timeout=10):
    try:
        # Do HEAD first; some servers block HEAD; if 405 or other, try GET (no body)
        r = requests.head(url, allow_redirects=True, timeout=timeout)
        if r.status_code >= 200 and r.status_code < 400:
            return True, r.status_code
        # try GET without downloading body
        r2 = requests.get(url, stream=True, allow_redirects=True, timeout=timeout)
        if r2.status_code >= 200 and r2.status_code < 400:
            return True, r2.status_code
        return False, r2.status_code
    except Exception as e:
        return False, str(e)

def main():
    ctx = ssl.create_default_context()
    imap = imaplib.IMAP4_SSL(IMAP_HOST, ssl_context=ctx)
    try:
        imap.login(EMAIL_ACCOUNT, EMAIL_PASSWORD)
    except imaplib.IMAP4.error as e:
        print(json.dumps({"error":"IMAP login failed", "details": str(e)}))
        return
    imap.select(MAILBOX)

    uids = search_recent_uids(imap, since_days=7)

    # Step 1: Facebook search
    fb_query_matches = None
    for uid in uids:
        msg = fetch_message(imap, uid)
        if msg is None:
            continue
        subject = get_header(msg, "Subject")
        frm = get_header(msg, "From")
        # check if subject/from indicates Facebook
        if re.search(r'facebook|security code', subject, flags=re.IGNORECASE) or re.search(r'facebookmail\.com|security@facebook\.com', frm, flags=re.IGNORECASE):
            text = get_text_from_msg(msg)
            code = find_facebook_code(text)
            fb_query_matches = {
                "facebook_code": code if code else None,
                "email_subject": subject,
                "email_from": frm,
                "email_date": iso_date_from_header(msg)
            }
            break

    if not fb_query_matches:
        fb_query_matches = {"error": "no matching Facebook message found in last 7 days"}

    # Print first result (or error)
    print(json.dumps({"step1": fb_query_matches}))

    # Step 2: TechServices reset search
    ts_query_matches = None
    for uid in uids:
        msg = fetch_message(imap, uid)
        if msg is None:
            continue
        subject = get_header(msg, "Subject")
        frm = get_header(msg, "From")
        # match TechServices by name or "password reset" subject or vendor domain
        if re.search(r'TechServices|password reset|reset your password', subject, flags=re.IGNORECASE) or re.search(r'techservices', frm, flags=re.IGNORECASE):
            text = get_text_from_msg(msg)
            url = find_first_url(text)
            url_valid = None
            url_status = None
            if url:
                ok, status = validate_url_head(url)
                url_valid = bool(ok)
                url_status = status
            ts_query_matches = {
                "techservices_reset_url": url if url else None,
                "email_subject": subject,
                "email_from": frm,
                "email_date": iso_date_from_header(msg),
                "url_valid": url_valid,
                "url_status": url_status
            }
            break

    if not ts_query_matches:
        ts_query_matches = {"error": "no matching TechServices password-reset message found in last 7 days"}

    print(json.dumps({"step2": ts_query_matches}))

    imap.logout()

if __name__ == "__main__":
    main()
```

Notes and explanations
- The script:
  - Logs into IMAP, lists messages SINCE 7 days ago, newest first.
  - For each message, checks Subject and From header for Facebook keywords and fetches the message text to extract a 5–8 digit code (using a targeted regex near “security code” first, then fallback).
  - For TechServices, it searches for subject or sender containing TechServices/password reset and extracts the first http(s) link found in the message body, then validates it using HTTP HEAD (falls back to GET if needed). It prints JSON for step1 and step2.
- Output formatting:
  - Example JSON you’ll get for a found Facebook code:
    {"step1": {"facebook_code": "123456", "email_subject": "Facebook security code", "email_from": "Facebook <security@facebookmail.com>", "email_date": "2026-03-12T09:23:00-07:00"}}
  - Example JSON for TechServices:
    {"step2": {"techservices_reset_url": "https://techservices.example.com/reset?token=abc", "email_subject": "Reset your password", "email_from": "noreply@techservices.example.com", "email_date": "2026-03-11T12:00:00-07:00", "url_valid": true, "url_status": 200}}
